import{_ as o,o as a,c as i,a2 as t}from"./chunks/framework.DtwafDNl.js";const h=JSON.parse('{"title":"IVR Flow Builder","description":"","frontmatter":{},"headers":[],"relativePath":"features/ivr.md","filePath":"features/ivr.md"}'),n={name:"features/ivr.md"};function r(l,e,s,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="ivr-flow-builder" tabindex="-1">IVR Flow Builder <a class="header-anchor" href="#ivr-flow-builder" aria-label="Permalink to &quot;IVR Flow Builder&quot;">‚Äã</a></h1><p>IVR Flow Builder is the visual editor for designing how calls move through Callytics. You build call routing with a drag-and-drop canvas instead of editing dialplan text, making it straightforward to design menus, queues, transfers, voicemail paths, and after-hours behavior.</p><p>Flows use a draft and publish model so you can prepare changes safely before they affect live calls. Published versions are tracked, and you can restore older versions with one click when a previous routing setup needs to be recovered.</p><p>Before a flow is published, Callytics validates the nodes and connections to catch missing configuration or invalid routing. The canvas also includes a minimap and auto-layout tools for keeping large call flows readable.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">‚Äã</a></h2><ul><li>Drag-and-drop call flow canvas</li><li>Draft editing before publishing to live calls</li><li>Flow version history</li><li>One-click restore of previous versions</li><li>Validation before publish</li><li>Canvas minimap for navigating large flows</li><li>Auto-layout for organizing complex diagrams</li></ul><h2 id="node-reference" tabindex="-1">Node Reference <a class="header-anchor" href="#node-reference" aria-label="Permalink to &quot;Node Reference&quot;">‚Äã</a></h2><blockquote><p>Terminal nodes (hangup, voicemail, callback, queue_login) have no outgoing edges except to webhook nodes. Any node ‚Äî including terminal nodes ‚Äî can connect to a webhook.</p></blockquote><h3 id="start" tabindex="-1">Start <a class="header-anchor" href="#start" aria-label="Permalink to &quot;Start&quot;">‚Äã</a></h3><p>The entry point for every flow. Each flow has exactly one Start node. It has no configuration options. It has a single outgoing edge that connects to the first step of the call.</p><h3 id="play-audio" tabindex="-1">Play Audio <a class="header-anchor" href="#play-audio" aria-label="Permalink to &quot;Play Audio&quot;">‚Äã</a></h3><p>Plays an uploaded audio file or a TTS-generated prompt to the caller.</p><ul><li><strong>Config:</strong> <code>audio_file_id</code> ‚Äî the ID of the audio file from the Audio library</li><li><strong>Behaviour:</strong> Playback runs via the ARI <code>play</code> command. The node resolves when playback completes.</li><li><strong>Edges:</strong> Single outgoing edge ‚Äî continues after playback finishes</li><li>IVR audio playback is never recorded, regardless of any recording settings on other nodes</li></ul><h3 id="get-digits" tabindex="-1">Get Digits <a class="header-anchor" href="#get-digits" aria-label="Permalink to &quot;Get Digits&quot;">‚Äã</a></h3><p>Waits for DTMF input from the caller and stores the collected digit string in a named call session variable for use downstream.</p><ul><li><strong>Config:</strong> variable name, expected digit count, timeout in milliseconds (default <code>10000ms</code>)</li><li><strong>Behaviour:</strong> Registers a <code>ChannelDtmfReceived</code> listener on the ARI channel. Resolves when the digit count is reached, the timeout elapses, or the caller hangs up.</li><li><strong>Edges:</strong> Single outgoing edge ‚Äî continues after digits are collected or timeout expires</li></ul><h3 id="menu" tabindex="-1">Menu <a class="header-anchor" href="#menu" aria-label="Permalink to &quot;Menu&quot;">‚Äã</a></h3><p>Routes the call based on which DTMF digit or digit sequence the caller pressed.</p><ul><li><strong>Config:</strong> Digit-to-edge mappings. Supports double-digit sequences ‚Äî for example, press <code>21</code> for HR, <code>22</code> for Finance.</li><li><strong>Behaviour:</strong> Waits for DTMF input, matches against configured patterns, and follows the corresponding edge. A subflow stack handles nested menu re-entry.</li><li><strong>Edges:</strong> One edge per configured digit pattern, plus separate edges for invalid input and timeout</li></ul><h3 id="business-hours" tabindex="-1">Business Hours <a class="header-anchor" href="#business-hours" aria-label="Permalink to &quot;Business Hours&quot;">‚Äã</a></h3><p>Routes the call based on configured weekly schedules.</p><ul><li><strong>Config:</strong> Weekly schedule per day with start and end times</li><li><strong>Behaviour:</strong> Checks the current server time against the configured schedule at the moment the node is reached</li><li><strong>Edges:</strong> Two edges ‚Äî <code>in-hours</code> and <code>out-of-hours</code></li><li><strong>Limitation:</strong> Midnight-crossing schedules (for example, 22:00‚Äì02:00) are not currently supported</li></ul><h3 id="transfer" tabindex="-1">Transfer <a class="header-anchor" href="#transfer" aria-label="Permalink to &quot;Transfer&quot;">‚Äã</a></h3><p>Bridges the caller to a SIP extension or a PSTN number via the configured trunk.</p><ul><li><strong>Config:</strong> destination type (extension or PSTN), destination value, trunk selection, <code>record_call</code> toggle</li><li><strong>Behaviour:</strong> Uses <code>formatDialNumber</code> to clean and format the number according to the trunk&#39;s <code>dial_format</code> field before dialing. When <code>record_call</code> is enabled, Stasis calls <code>POST /ari/bridges/{bridgeId}/record</code> to start bridge recording.</li><li><strong>Edges:</strong> Single outgoing edge after transfer completes (hangup or disconnect)</li></ul><h3 id="hunt-group" tabindex="-1">Hunt Group <a class="header-anchor" href="#hunt-group" aria-label="Permalink to &quot;Hunt Group&quot;">‚Äã</a></h3><p>Tries multiple destinations with one of three distribution strategies.</p><ul><li><strong>Config:</strong> destination list, strategy, <code>record_call</code> toggle</li><li><strong>Strategies:</strong><ul><li><em>Group (simultaneous)</em> ‚Äî originates all destinations at once via ARI. Takes the first channel to answer and immediately hangs up all losing channels.</li><li><em>One by one ordered</em> ‚Äî tries destinations in the configured order. Moves to the next on no-answer or busy.</li><li><em>One by one random</em> ‚Äî same as ordered, but shuffles the destination list on each call.</li></ul></li><li><strong>Recording:</strong> When <code>record_call</code> is enabled, bridge recording starts on the winning channel via ARI.</li><li><strong>Edges:</strong> Single outgoing edge after the hunt group call ends</li></ul><h3 id="queue" tabindex="-1">Queue <a class="header-anchor" href="#queue" aria-label="Permalink to &quot;Queue&quot;">‚Äã</a></h3><p>Places the caller in a waiting queue until an available operator is matched.</p><ul><li><strong>Config:</strong> queue selection, timeout duration, abandon edge, timeout edge</li><li><strong>Behaviour:</strong><ul><li>Stasis checks <code>queue:&lt;id&gt;:operators</code> in Redis for logged-in operators</li><li>Polls Redis every 500ms waiting for an available operator</li><li>When matched, Stasis creates a <code>mixing,dtmf_events</code> ARI bridge between the caller channel and the operator channel</li><li>Queue live state is Redis only ‚Äî PostgreSQL is never polled for queue state</li></ul></li><li><strong>Edges:</strong> Outgoing edges for abandoned (caller hangs up) and timeout (max wait exceeded)</li></ul><h3 id="queue-login" tabindex="-1">Queue Login <a class="header-anchor" href="#queue-login" aria-label="Permalink to &quot;Queue Login&quot;">‚Äã</a></h3><p>Lets a call-center operator log in or out of a queue from their softphone using a PIN.</p><ul><li><strong>Config:</strong> queue selection</li><li><strong>Behaviour:</strong><ul><li>Stasis prompts the operator for their PIN via DTMF</li><li>Matches the input against <code>operators.pin_hash</code> in the database</li><li>On match, Stasis writes to Redis: <ul><li><code>operator:&lt;id&gt;:queue</code> = queue ID</li><li><code>operator:&lt;id&gt;:channel</code> = ARI channel ID</li><li>Adds the operator&#39;s channel to the <code>queue:&lt;id&gt;:operators</code> set</li></ul></li><li>Operator dials <code>#</code> during the PIN prompt to log out</li></ul></li><li><strong>Edges:</strong> Terminal node ‚Äî no outgoing edges except to webhook</li></ul><h3 id="conference" tabindex="-1">Conference <a class="header-anchor" href="#conference" aria-label="Permalink to &quot;Conference&quot;">‚Äã</a></h3><p>Places the caller into a named ARI conference bridge. Multiple callers joining the same room name are bridged together in a single mixing bridge.</p><ul><li><strong>Config:</strong> room name</li><li><strong>Edges:</strong> Resolves when the caller leaves the conference or hangs up</li></ul><h3 id="callback" tabindex="-1">Callback <a class="header-anchor" href="#callback" aria-label="Permalink to &quot;Callback&quot;">‚Äã</a></h3><p>Records the caller&#39;s callback number and stores it in the database. The caller either enters their number via DTMF or confirms their caller ID.</p><ul><li><strong>Config:</strong> callback number source (DTMF entry or caller ID), optional confirmation prompt</li><li><strong>Behaviour:</strong> Stores the callback record as pending. The Callbacks page in the UI shows pending callbacks. An operator initiates the return call from the UI.</li><li><strong>Edges:</strong> Terminal node ‚Äî no outgoing edges except to webhook</li></ul><h3 id="voicemail" tabindex="-1">Voicemail <a class="header-anchor" href="#voicemail" aria-label="Permalink to &quot;Voicemail&quot;">‚Äã</a></h3><p>Records a voice message from the caller via ARI channel recording.</p><ul><li><strong>Config:</strong> start audio prompt (required), maximum recording duration</li><li><strong>Behaviour:</strong> Stasis calls the ARI channel recording endpoint. Recording saved as a <code>.ulaw</code> file in the <code>asterisk_recordings</code> volume.</li><li><strong>Edges:</strong> Terminal node ‚Äî no outgoing edges except to webhook</li></ul><h3 id="webhook" tabindex="-1">Webhook <a class="header-anchor" href="#webhook" aria-label="Permalink to &quot;Webhook&quot;">‚Äã</a></h3><p>Sends an async fire-and-forget HTTP POST to a configured URL.</p><ul><li><strong>Config:</strong> URL, optional headers, optional payload template</li><li><strong>Behaviour:</strong> The HTTP request is fired without awaiting a response. Call flow execution continues immediately ‚Äî the webhook never blocks the call. Can be connected from any node, including terminal nodes (hangup, voicemail, callback, queue_login).</li><li><strong>Canvas:</strong> Edges to and from webhook nodes render with dashed lines. The node card shows a small &quot;async&quot; label.</li><li><strong>Edges:</strong> Single outgoing edge (call flow continues after webhook is dispatched, not after HTTP response)</li></ul><h3 id="hangup" tabindex="-1">Hangup <a class="header-anchor" href="#hangup" aria-label="Permalink to &quot;Hangup&quot;">‚Äã</a></h3><p>Ends the call immediately.</p><ul><li><strong>Edges:</strong> Terminal node ‚Äî no outgoing edges except to webhook</li></ul>',49)])])}const p=o(n,[["render",r]]);export{h as __pageData,p as default};
